import os
from io import StringIO
from lxml import etree

def process_soap_request(xml_data):
    # Validate against DTD
    dtd_path = 'path/to/schema.dtd'
    if not os.path.exists(dtd_path):
        return 'DTD schema file does not exist.'

    dtd_root = etree.DTD(os.path.abspath(dtd_path))
    parser = etree.XMLParser(huge_tree=True)
    try:
        tree = dtd_root.parse(StringIO(xml_data), parser=parser)
    except etree.DocumentInvalid as e:
        return f'DTD validation failed: {str(e)}'

    # Extract message body
    soap_envelope_ns = '{http://schemas.xmlsoap.org/soap/envelope/}'
    body_tag = tree.xpath(f'//{soap_envelope_ns}Body')
    if not body_tag:
        return 'SOAP envelope is malformed or missing the Body element.'

    body_element = body_tag[0]
    message_body = etree.tostring(body_element, encoding='unicode')

    return {'message': message_body}